#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,y,z;
    int cnt,ans;
}a[100010],b[100010];
int lowbit(int x)
{
    return x&-x;
}
int sum[500010];
long long ans[100010],n,k,tot;
void update(int x,int v)
{
    for(int i=x;i<=k;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
bool cmpx(node a,node b)
{
    return a.x<b.x||(a.x==b.x&&a.y<b.y)||(a.x==b.x&&a.y==b.y&&a.z<b.z);
}
bool cmpy(node a,node b)
{
    return a.y<b.y||(a.y==b.y&&a.z<b.z);
}
void cdq(int l,int r)
{
    if(l==r)
    {
        return;
    }
    int mid=(l+r)>>1;
    cdq(l,mid);
    cdq(mid+1,r);
    sort(a+l,a+1+mid,cmpy);
    sort(a+mid+1,a+1+r,cmpy);
    int i=l,j=mid+1;
    while(j<=r)
    {
        while(i<=mid&&a[i].y<=a[j].y)
        {
            update(a[i].z,a[i].cnt);
            i++;
        }
        a[j].ans+=query(a[j].z);
        j++;
    }
    for(int k=l;k<i;k++)
    {
        update(a[k].z,-a[k].cnt);
    }
}
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d",&b[i].x,&b[i].y,&b[i].z);
    }
    sort(b+1,b+1+n,cmpx);
    int now=0,m=0;
    for(int i=1;i<=n;i++)
    {
        now++;
        if(b[i].x!=b[i+1].x||b[i].y!=b[i+1].y||b[i].z!=b[i+1].z)
        {
            a[++m]=b[i];
            a[m].cnt=now;
            now=0;
        }
    }
    cdq(1,m);
    for(int i=1;i<=m;i++)
    {
        ans[a[i].ans+a[i].cnt-1]+=a[i].cnt;
    }
    for(int i=0;i<n;i++)
    {
        printf("%d\n",ans[i]);
    }
    return 0;
}
